SELECT *
FROM (

  ORDER BY likeCount DESC, TBL_BOARD.REG_DATE DESC
)
WHERE ROWNUM <= #{value}

SELECT *
FROM (

  ORDER BY viewCount DESC, TBL_BOARD.REG_DATE DESC
)
WHERE ROWNUM <= #{value}

SELECT *
FROM (

  ORDER BY TBL_BOARD.REG_DATE DESC
)
WHERE ROWNUM <= #{value}

SELECT *
FROM (



    AND TBL_BOARD.BOARD_TYPE = #{boardType}




      ORDER BY likeCount DESC, TBL_BOARD.REG_DATE DESC


      ORDER BY viewCount DESC, TBL_BOARD.REG_DATE DESC


      ORDER BY TBL_BOARD.REG_DATE DESC


)
WHERE ROWNUM <= #{limit}

SELECT *
FROM (

  AND TBL_BOARD.USER_ID = #{userId}
  ORDER BY TBL_BOARD.REG_DATE DESC
)
WHERE ROWNUM <= #{limit}
